"""Distilled SCF method-selector (auto-generated by train_selector.py).
predict(features:dict)->str ; features: natom,charge,mult,is_dft,open_shell,transition_metal."""

def predict(f):
    if f.get("charge",0) <= -1:
        return "ediis"
    else:
        if f.get("charge",0) <= 1:
            if f.get("is_uhf",0) <= 0.5:
                if f.get("is_dft",0) <= 0.5:
                    return "cdiis"
                else:
                    return "cdiis"
            else:
                if f.get("mult",0) <= 4:
                    return "cdiis"
                else:
                    return "cdiis"
        else:
            if f.get("is_dft",0) <= 0.5:
                return "cdiis"
            else:
                return "ediis"
